import './ThemeProvider.scss';

import React, { useEffect, useState } from 'react';

import { classNames } from '../../helpers/classnames';
import type { ThemeProviderProps } from './ThemeProvider.types';

export const ThemeProvider: React.FC<ThemeProviderProps> = ({
	children,
	isRoot = false,
	theme = 'light',
	rootSelector = 'body',
	className = '',
	...rest
}) => {
	const [themeClass, setThemeClass] = useState<'ds-theme--dark' | 'ds-theme--light'>('ds-theme--light');

	useEffect(() => {
		const rootEl = document.querySelector(rootSelector);
		const newThemeClassName = theme === 'light' ? 'ds-theme--light' : 'ds-theme--dark';
		const oldThemeClassName = themeClass;

		if (isRoot) {
			rootEl.classList.remove(oldThemeClassName);
			rootEl.classList.add(newThemeClassName);
		}

		setThemeClass(newThemeClassName);
	}, [theme, isRoot, rootSelector, themeClass]);

	return (
		<div data-testid="ThemeProvider" className={classNames(!isRoot && themeClass, className)} {...rest}>
			{children}
		</div>
	);
};
